code.python:
def sorted_squares(nums):
    n = len(nums)
    res = [0] * n
    lo, hi = 0, n - 1
    for k in range(n - 1, -1, -1):
        if abs(nums[lo]) > abs(nums[hi]):
            res[k] = nums[lo] * nums[lo]
            lo += 1
        else:
            res[k] = nums[hi] * nums[hi]
            hi -= 1
    return res

code.javascript:
function sortedSquares(nums) {
  const n = nums.length;
  const res = new Array(n).fill(0);
  let lo = 0;
  let hi = n - 1;
  for (let k = n - 1; k >= 0; k--) {
    if (Math.abs(nums[lo]) > Math.abs(nums[hi])) {
      res[k] = nums[lo] * nums[lo];
      lo++;
    } else {
      res[k] = nums[hi] * nums[hi];
      hi--;
    }
  }
  return res;
}

code.typescript:
function sortedSquares(nums: number[]): number[] {
  const n = nums.length;
  const res = new Array<number>(n).fill(0);
  let lo = 0;
  let hi = n - 1;
  for (let k = n - 1; k >= 0; k--) {
    if (Math.abs(nums[lo]) > Math.abs(nums[hi])) {
      res[k] = nums[lo] * nums[lo];
      lo++;
    } else {
      res[k] = nums[hi] * nums[hi];
      hi--;
    }
  }
  return res;
}
